# Approach: A cell is inside if it's between the leftmost/rightmost walls on its row
# AND between the topmost/bottommost walls on its column

def rect_inside(grid, wall_color):
    H, W = len(grid), len(grid[0])
    # For each row, find leftmost and rightmost wall
    row_left = [None]*H
    row_right = [None]*H
    for r in range(H):
        for c in range(W):
            if grid[r][c] == wall_color:
                if row_left[r] is None:
                    row_left[r] = c
                row_right[r] = c
    # For each col, find topmost and bottommost wall
    col_top = [None]*W
    col_bot = [None]*W
    for c in range(W):
        for r in range(H):
            if grid[r][c] == wall_color:
                if col_top[c] is None:
                    col_top[c] = r
                col_bot[c] = r

    inside = [[False]*W for _ in range(H)]
    for r in range(H):
        for c in range(W):
            if grid[r][c] == wall_color:
                continue
            if row_left[r] is not None and row_right[r] is not None:
                if row_left[r] < c < row_right[r]:
                    if col_top[c] is not None and col_bot[c] is not None:
                        if col_top[c] < r < col_bot[c]:
                            inside[r][c] = True
    return inside

# Test on all examples
