    inp = np.array(s['input']).tolist()
    out = np.array(s['output']).tolist()
    bg = inp[0][0]

    # Determine wall_color and fill_color
    diff = np.array(inp) != np.array(out)
    fill_color = int(np.array(out)[diff][0])

    non_bg = set()
    for r in range(len(inp)):
        for c in range(len(inp[0])):
            if inp[r][c] != bg and inp[r][c] != fill_color:
                non_bg.add(inp[r][c])

    # Wall color is the one forming the boundary (most frequent non-bg, non-fill)
    from collections import Counter
    counts = Counter()
    for r in range(len(inp)):
        for c in range(len(inp[0])):
            if inp[r][c] != bg:
                counts[inp[r][c]] += 1
    # The wall color should be the boundary-forming one
    wall_candidates = [c for c in counts if c != fill_color]
    wall_color = max(wall_candidates, key=lambda c: counts[c])

    inside = rect_inside(inp, wall_color)

    correct = 0
    total = 0
    mismatches = 0
    for r in range(len(inp)):
        for c in range(len(inp[0])):
            if inp[r][c] not in [wall_color]:
                total += 1
                should_fill = out[r][c] == fill_color
                is_inside = inside[r][c]
                if should_fill == is_inside:
                    correct += 1
                else:
                    mismatches += 1

    print(f"Example {i}: wall={wall_color}, fill={fill_color}")
    print(f"  Rect inside accuracy: {correct}/{total} (mismatches: {mismatches})")

