# Great! Opening detection works. Now let me implement the full algorithm.

def solve(grid):
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    # Find all non-bg colors and their positions
    color_positions = {}
    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg:
                color_positions.setdefault(grid[r][c], []).append((r, c))

    if not color_positions:
        return grid

    wall_color = max(color_positions, key=lambda c: len(color_positions[c]))
    wall_cells = set(color_positions[wall_color])
    wall_rows = [r for r, c in wall_cells]
    wall_cols = [c for r, c in wall_cells]
    min_wr, max_wr = min(wall_rows), max(wall_rows)
    min_wc, max_wc = min(wall_cols), max(wall_cols)
    bbox_center_r = (min_wr + max_wr) / 2
    bbox_center_c = (min_wc + max_wc) / 2

    other_colors = [c for c in color_positions if c != wall_color]

    fill_color = None
    min_dist = float('inf')
    for color in other_colors:
        for r, c in color_positions[color]:
            dist = abs(r - bbox_center_r) + abs(c - bbox_center_c)
            if dist < min_dist:
